                      <button 
                        onClick={() => onManageWithdrawal(tx.id, TransactionStatus.REJECTED)}
                        className="flex-1 py-2 bg-rose-600/20 text-rose-400 hover:bg-rose-600 hover:text-white rounded-lg text-xs font-bold transition-all"
                      >
                        Reject
                      </button>
                    </div>
                  </div>
                );
              })
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default AdminPanel;

import React, { useState, useEffect, useCallback } from 'react';
import { AppState, User, TransactionType, TransactionStatus } from './types';
import { loadState, saveState, simulateDeposit, processDailyRoi } from './store';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import Wallet from './components/Wallet';
import AdminPanel from './components/AdminPanel';
import { INITIAL_PACKAGES } from './constants';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(loadState());
  const [view, setView] = useState<string>('auth'); // auth, dashboard, wallet, admin, referrals, packages
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [refCode, setRefCode] = useState('');

  // Sync with LocalStorage
  useEffect(() => {
    saveState(state);
  }, [state]);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const user = state.users.find(u => u.email === email);
    if (user) {
      setState(prev => ({ ...prev, currentUser: user }));
      setView('dashboard');
    } else {
      alert('User not found. Try registering!');
    }
  };

  const handleRegister = (e: React.FormEvent) => {
    e.preventDefault();
    if (state.users.some(u => u.email === email)) {
      alert('Email already exists');
      return;
    }

    const newUser: User = {
      id: Math.random().toString(36).substr(2, 9),
      email,
      referralCode: email.split('@')[0].toUpperCase() + Math.floor(Math.random() * 1000),
      referredBy: refCode || undefined,
      usdtDepositAddress: 'T' + Math.random().toString(36).substr(2, 33).toUpperCase(),
      capitalBalance: 0,
      profitBalance: 0,
      totalEarned: 0,
      isActive: true,
      isAdmin: false,
      referralCount: 0,
      referralEarnings: 0
    };

    setState(prev => ({
      ...prev,
      users: [...prev.users, newUser],
      currentUser: newUser
    }));
    setView('dashboard');
  };

  const handleLogout = () => {
    setState(prev => ({ ...prev, currentUser: null }));
    setView('auth');
  };

  const handleDeposit = (amount: number) => {
    if (!state.currentUser) return;
    const newState = simulateDeposit(state, state.currentUser.id, amount);
    setState(newState);
    alert(`Success! ${amount} USDT has been credited to your node capital.`);
  };

  const handleWithdrawalRequest = (amount: number, address: string) => {
    if (!state.currentUser || amount > state.currentUser.profitBalance) return;

    const newTx = {
      id: Math.random().toString(36).substr(2, 9),
      userId: state.currentUser.id,
      type: TransactionType.WITHDRAWAL,
      amount,
      status: TransactionStatus.PENDING,
      timestamp: Date.now(),
      description: `Withdrawal request to ${address}`
    };

    setState(prev => {
      const updatedUsers = prev.users.map(u => 
        u.id === state.currentUser?.id ? { ...u, profitBalance: u.profitBalance - amount } : u
      );
      return {
        ...prev,
        users: updatedUsers,
        transactions: [newTx, ...prev.transactions],
        currentUser: updatedUsers.find(u => u.id === state.currentUser?.id) || null
      };
    });
    alert('Withdrawal request submitted for approval.');
  };

  const handleTriggerRoi = () => {
    const newState = processDailyRoi(state);
    setState(newState);
    alert('Daily ROI and Referral distributions processed for all active nodes.');
  };

  const handleManageWithdrawal = (txId: string, status: TransactionStatus) => {
    setState(prev => {
      const tx = prev.transactions.find(t => t.id === txId);
      if (!tx) return prev;

      const updatedTransactions = prev.transactions.map(t => 
        t.id === txId ? { ...t, status } : t
      );

      let updatedUsers = [...prev.users];
      // If rejected, refund the user
      if (status === TransactionStatus.REJECTED) {
        updatedUsers = prev.users.map(u => 
          u.id === tx.userId ? { ...u, profitBalance: u.profitBalance + tx.amount } : u
        );
      }

      return {
        ...prev,
        transactions: updatedTransactions,
        users: updatedUsers,
        currentUser: prev.currentUser ? updatedUsers.find(u => u.id === prev.currentUser?.id) || null : null
      };
    });
  };

