  const [password, setPassword] = useState('');
  const [refCode, setRefCode] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  useEffect(() => {
    saveState(state);
  }, [state]);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    // Simulate network delay for professional feel
    await new Promise(r => setTimeout(r, 800));

    const user = state.users.find(u => u.email === email);
    if (user) {
      setState(prev => ({ ...prev, currentUser: user }));
      setView('dashboard');
    } else {
      alert('Authentication failed. Check credentials.');
    }
    setIsLoading(false);
  };

  const handleRegister = async (e: React.FormEvent) => {
    e.preventDefault();
    if (state.users.some(u => u.email === email)) {
      alert('Identity already registered.');
      return;
    }
    setIsLoading(true);
    await new Promise(r => setTimeout(r, 1200));

    const newUser: User = {
      id: Math.random().toString(36).substr(2, 9),
      email,
      referralCode: email.split('@')[0].toUpperCase() + Math.floor(Math.random() * 1000),
      referredBy: refCode || undefined,
      usdtDepositAddress: 'T' + Math.random().toString(36).substr(2, 33).toUpperCase(),
      capitalBalance: 0,
      profitBalance: 0,
      totalEarned: 0,
      isActive: true,
      isAdmin: false,
      referralCount: 0,
      referralEarnings: 0
    };

    setState(prev => ({
      ...prev,
      users: [...prev.users, newUser],
      currentUser: newUser
    }));
    setView('dashboard');
    setIsLoading(false);
  };

  const handleLogout = () => {
    setState(prev => ({ ...prev, currentUser: null }));
