    e.preventDefault();
    if (state.users.some(u => u.email === email)) {
      alert('Identity already registered.');
      return;
    }
    setIsLoading(true);
    await new Promise(r => setTimeout(r, 1200));

    const newUser: User = {
      id: Math.random().toString(36).substr(2, 9),
      email,
      referralCode: email.split('@')[0].toUpperCase() + Math.floor(Math.random() * 1000),
