const STORAGE_KEY = 'usdt_earning_pool_state';

const generateId = () => Math.random().toString(36).substr(2, 9);
const generateAddress = () => 'T' + Math.random().toString(36).substr(2, 33).toUpperCase();

const initialState: AppState = {
  currentUser: null,
  users: [
    {
      id: 'admin',
      email: 'admin@quantumearn.com',
      referralCode: 'ADMIN_ROOT',
      usdtDepositAddress: 'TADMIN1234567890',
      capitalBalance: 0,
      profitBalance: 0,
      totalEarned: 0,
      isActive: true,
      isAdmin: true,
      referralCount: 0,
      referralEarnings: 0
    }
  ],
  packages: INITIAL_PACKAGES,
  activePackages: [],
  transactions: [],
  platformSettings: {
    isRoiEnabled: true,
    referralLevels: REF_LEVELS,
    minWithdrawal: 10,
    platformPaused: false
  }
};

export const loadState = (): AppState => {
  const saved = localStorage.getItem(STORAGE_KEY);
  if (saved) {
    try {
      return JSON.parse(saved);
    } catch (e) {
      return initialState;
    }
  }
  return initialState;
};

export const saveState = (state: AppState) => {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
};

// Simulation Logic
export const simulateDeposit = (state: AppState, userId: string, amount: number): AppState => {
  const user = state.users.find(u => u.id === userId);
  if (!user) return state;

  const newTx: Transaction = {
    id: generateId(),
    userId,
    type: TransactionType.DEPOSIT,
    amount,
    status: TransactionStatus.COMPLETED,
    txHash: '0x' + generateId() + generateId(),
    timestamp: Date.now(),
    description: `Deposit of ${amount} USDT confirmed.`
  };

  // Check which package to auto-activate
  const pkg = state.packages.find(p => amount >= p.minAmount && amount <= p.maxAmount);

  const newState = {
    ...state,
    users: state.users.map(u => u.id === userId ? {
      ...u,
      capitalBalance: u.capitalBalance + amount
    } : u),
    transactions: [newTx, ...state.transactions],
  };

  if (pkg) {
    const activePkg: UserPackage = {
      id: generateId(),
      packageId: pkg.id,
      amount,
      activatedAt: Date.now(),
      isActive: true,
      totalEarned: 0
    };
    newState.activePackages = [...state.activePackages, activePkg];
    // Link to user if needed (in a real DB this is a relation, here we store globally)
    // Note: In our current model UserPackage doesn't have userId, let's fix that.
    (activePkg as any).userId = userId;
  }

  if (newState.currentUser?.id === userId) {
    newState.currentUser = newState.users.find(u => u.id === userId) || null;
  }

  return newState;
};

export const processDailyRoi = (state: AppState): AppState => {
  if (!state.platformSettings.isRoiEnabled || state.platformSettings.platformPaused) return state;

  let newState = { ...state };
  const roiTransactions: Transaction[] = [];

  const updatedActivePackages = state.activePackages.map(ap => {
    if (!ap.isActive) return ap;

    const pkg = state.packages.find(p => p.id === ap.packageId);
    if (!pkg) return ap;

    const dailyPercent = state.platformSettings.roiOverride || pkg.dailyRoi;
    const earnings = ap.amount * (dailyPercent / 100);

    // Create ROI transaction
    roiTransactions.push({
      id: generateId(),
      userId: (ap as any).userId,
      type: TransactionType.ROI,
      amount: earnings,
      status: TransactionStatus.COMPLETED,
      timestamp: Date.now(),
      description: `Daily ROI from ${pkg.name}`
    });

    // Handle referral distribution
    distributeReferrals(newState, (ap as any).userId, earnings, roiTransactions);

    return {
      ...ap,
      totalEarned: ap.totalEarned + earnings
    };
  });

  // Update User Balances
  const userUpdates = new Map<string, number>();
  roiTransactions.forEach(tx => {
    userUpdates.set(tx.userId, (userUpdates.get(tx.userId) || 0) + tx.amount);
  });

  newState.users = newState.users.map(u => {
    const bonus = userUpdates.get(u.id);
    if (bonus) {
      return {
        ...u,
        profitBalance: u.profitBalance + bonus,
        totalEarned: u.totalEarned + bonus
      };
    }
    return u;
  });

  newState.activePackages = updatedActivePackages;
  newState.transactions = [...roiTransactions, ...newState.transactions];

  if (newState.currentUser) {
    newState.currentUser = newState.users.find(u => u.id === newState.currentUser?.id) || null;
  }

  return newState;
};

const distributeReferrals = (state: AppState, userId: string, earnings: number, transactions: Transaction[]) => {
  let currentUser = state.users.find(u => u.id === userId);
  if (!currentUser || !currentUser.referredBy) return;

  let currentLevel = 1;
  let referrerId = currentUser.referredBy;

  while (currentLevel <= state.platformSettings.referralLevels.length) {
    const referrer = state.users.find(u => u.referralCode === referrerId || u.id === referrerId);
    if (!referrer) break;

    const config = state.platformSettings.referralLevels.find(l => l.level === currentLevel);
    if (config) {
      const commission = earnings * (config.percentage / 100);
      transactions.push({
        id: generateId(),
        userId: referrer.id,
        type: TransactionType.REFERRAL,
        amount: commission,
        status: TransactionStatus.COMPLETED,
        timestamp: Date.now(),
        description: `Level ${currentLevel} Referral Commission from User ${userId}`
      });
    }

    if (!referrer.referredBy) break;
    referrerId = referrer.referredBy;
    currentLevel++;
  }
};

