import { motion, AnimatePresence } from 'framer-motion';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(loadState());
  const [view, setView] = useState<string>('auth');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [refCode, setRefCode] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  useEffect(() => {
    saveState(state);
  }, [state]);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    await new Promise(r => setTimeout(r, 1000));

    const user = state.users.find(u => u.email === email);
    if (user) {
      setState(prev => ({ ...prev, currentUser: user }));
      setView('dashboard');
    } else {
      alert('Authentication denied.');
    }
    setIsLoading(false);
  };

  const handleRegister = async (e: React.FormEvent) => {
    e.preventDefault();
    if (state.users.some(u => u.email === email)) {
      alert('Email registered.');
      return;
    }
    setIsLoading(true);
    await new Promise(r => setTimeout(r, 1500));

    const newUser: User = {
      id: Math.random().toString(36).substr(2, 9),
      email,
      referralCode: email.split('@')[0].toUpperCase() + Math.floor(Math.random() * 1000),
      referredBy: refCode || undefined,
      usdtDepositAddress: 'T' + Math.random().toString(36).substr(2, 33).toUpperCase(),
      capitalBalance: 0,
      profitBalance: 0,
      totalEarned: 0,
      isActive: true,
      isAdmin: false,
      referralCount: 0,
      referralEarnings: 0
    };

    setState(prev => ({
      ...prev,
      users: [...prev.users, newUser],
      currentUser: newUser
    }));
    setView('dashboard');
    setIsLoading(false);
  };

  const handleLogout = () => {
    setState(prev => ({ ...prev, currentUser: null }));
    setView('auth');
  };

  if (!state.currentUser) {
    return (
      <div className="min-h-screen bg-black flex flex-col lg:flex-row relative">
