            <div className="space-y-1">
              <p className="text-2xl font-black mono tracking-tighter">128</p>
              <p className="text-[10px] font-bold text-white/30 uppercase tracking-widest">Node Clusters</p>
            </div>
            <div className="space-y-1">
              <p className="text-2xl font-black mono tracking-tighter">$42.0B</p>
              <p className="text-[10px] font-bold text-white/30 uppercase tracking-widest">Total Valuation</p>
            </div>
          </div>
        </div>

        {/* Right Form Section */}
        <div className="w-full lg:w-[35%] min-h-screen bg-black flex items-center justify-center p-12 lg:p-24">
          <motion.div 
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            className="w-full max-w-sm space-y-12"
          >
            <div>
              <h2 className="text-[10px] font-black uppercase tracking-[0.5em] text-white/40 mb-2">Gate Entry</h2>
              <p className="text-2xl font-bold tracking-tight">Access Protocol</p>
