                <input 
                  type="email" 
                  required
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  className="w-full bg-transparent border-b border-white/20 py-3 outline-none focus:border-white transition-colors font-medium text-white"
                  placeholder="client@quantum.io"
                />
              </div>

              <div className="space-y-2 group">
                <p className="text-[10px] font-black uppercase tracking-widest text-white/30 group-focus-within:text-white transition-colors">Secure Hash</p>
                <input 
                  type="password" 
                  required
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  className="w-full bg-transparent border-b border-white/20 py-3 outline-none focus:border-white transition-colors font-medium text-white"
                  placeholder="••••••••"
                />
