              )}

              <button 
                type="submit"
                disabled={isLoading}
                className="w-full py-5 bg-white text-black text-xs font-black uppercase tracking-[0.3em] hover:bg-white/90 active:scale-[0.98] transition-all flex items-center justify-center gap-4"
              >
                {isLoading ? (
                  <div className="w-4 h-4 border-2 border-black/20 border-t-black rounded-full animate-spin"></div>
                ) : (
                  view === 'auth' ? 'Initialize' : 'Register'
                )}
              </button>

              <div className="text-center pt-4">
                 <button 
                  type="button"
                  onClick={() => setView(view === 'auth' ? 'register' : 'auth')}
                  className="text-[10px] font-black uppercase tracking-widest text-white/30 hover:text-white transition-colors"
                 >
                   {view === 'auth' ? "Request Membership" : "Return to Login"}
                 </button>
              </div>
            </form>
          </motion.div>
        </div>
      </div>
    );
  }

  return (
    <Layout 
      user={state.currentUser} 
      onLogout={handleLogout} 
      onNavigate={setView}
      currentView={view}
    >
      <AnimatePresence mode="wait">
        <motion.div
          key={view}
          initial={{ opacity: 0, y: 5 }}
          animate={{ opacity: 1, y: 0 }}
          exit={{ opacity: 0, y: -5 }}
          transition={{ duration: 0.3 }}
        >
          {view === 'dashboard' && (
            <Dashboard 
              user={state.currentUser} 
              transactions={state.transactions.filter(tx => tx.userId === state.currentUser?.id)}
              activePackages={state.activePackages.filter(p => (p as any).userId === state.currentUser?.id)}
            />
          )}

          {view === 'wallet' && (
            <Wallet 
              user={state.currentUser} 
              onDepositSim={(a) => setState(simulateDeposit(state, state.currentUser!.id, a))}
              onWithdrawRequest={(amount, address) => {
                if (amount > state.currentUser!.profitBalance) return;
                const newTx = {
                  id: Math.random().toString(36).substr(2, 9),
                  userId: state.currentUser!.id,
                  type: TransactionType.WITHDRAWAL,
                  amount,
                  status: TransactionStatus.PENDING,
                  timestamp: Date.now(),
                  description: `Vault extraction to ${address}`
                };
                setState(prev => {
                  const updatedUsers = prev.users.map(u => u.id === state.currentUser?.id ? { ...u, profitBalance: u.profitBalance - amount } : u);
                  return { ...prev, users: updatedUsers, transactions: [newTx, ...prev.transactions], currentUser: updatedUsers.find(u => u.id === state.currentUser?.id) || null };
                });
              }}
            />
          )}

          {view === 'packages' && (
