                              <span className="text-[10px] font-bold uppercase tracking-widest opacity-40">Ceiling</span>
                              <span className="text-sm font-bold mono">{pkg.maxAmount} USDT</span>
                            </div>
                         </div>
                         <button 
                          onClick={() => setView('wallet')}
                          className="w-full py-4 border border-white/20 group-hover:bg-black group-hover:text-white group-hover:border-black text-[10px] font-black uppercase tracking-[0.3em] transition-all"
                         >
                           Select Tier
                         </button>
                       </div>
                     </div>
                   </div>
                 ))}
               </div>
            </div>
          )}

          {view === 'referrals' && (
            <div className="space-y-24 max-w-7xl mx-auto">
               <div className="flex flex-col lg:flex-row justify-between items-end gap-12">
                  <div className="space-y-6 flex-1">
                    <h1 className="text-6xl lg:text-9xl font-black uppercase tracking-tighter leading-[0.85]">Affiliate<br/>Network.</h1>
                    <p className="serif italic text-2xl text-white/50 max-w-xl">
                      Expansion rewards for the sophisticated elite. Multiply yield through deep-tier network effects.
                    </p>
                  </div>
                  <div className="w-full lg:w-96 p-10 bg-white text-black space-y-6">
                    <p className="text-[10px] font-black uppercase tracking-widest leading-none">Share protocol key</p>
                    <p className="text-xl font-black mono tracking-widest truncate">{state.currentUser.referralCode}</p>
                    <button className="w-full py-3 bg-black text-white text-[10px] font-black uppercase tracking-[0.2em] hover:bg-black/90 transition-all">
                      Copy Link
                    </button>
                  </div>
               </div>

               <div className="grid grid-cols-1 md:grid-cols-3 border-t border-l border-white/10">
                  {[
                    { level: 1, rate: 10, label: 'Primary' },
                    { level: 2, rate: 5, label: 'Secondary' },
                    { level: 3, rate: 2, label: 'Tertiary' }
                  ].map((tier) => (
                    <div key={tier.level} className="border-r border-b border-white/10 p-12 space-y-8">
