              onManageWithdrawal={(id, status) => {
                const tx = state.transactions.find(t => t.id === id);
                if (!tx) return;
                setState(prev => {
                  const updatedTxs = prev.transactions.map(t => t.id === id ? {...t, status} : t);
                  let updatedUsers = prev.users;
                  if (status === TransactionStatus.REJECTED) {
                    updatedUsers = prev.users.map(u => u.id === tx.userId ? {...u, profitBalance: u.profitBalance + tx.amount} : u);
                  }
                  return {...prev, transactions: updatedTxs, users: updatedUsers, currentUser: prev.currentUser ? updatedUsers.find(u => u.id === prev.currentUser?.id) || null : null};
                });
