          {user && (
            <div className="flex items-center gap-6">
              <div className="flex flex-col items-end">
                <p className="text-[10px] font-black text-white/40 uppercase tracking-widest">Available Balance</p>
                <p className="text-sm font-bold mono tracking-tighter">{user.profitBalance.toFixed(2)} USDT</p>
              </div>
              <div className="w-10 h-10 border border-white/20 flex items-center justify-center hover:border-white transition-colors cursor-pointer">
                <i className="fa-solid fa-user text-sm"></i>
              </div>
            </div>
          )}
