import React, { useState, useEffect } from 'react';
import { AppState, User, TransactionType, TransactionStatus } from './types.ts';
import { loadState, saveState, simulateDeposit, processDailyRoi } from './store.ts';
import Layout from './components/Layout.tsx';
import Dashboard from './components/Dashboard.tsx';
import Wallet from './components/Wallet.tsx';
import AdminPanel from './components/AdminPanel.tsx';
import { INITIAL_PACKAGES } from './constants.tsx';
import { motion, AnimatePresence } from 'framer-motion';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(loadState());
  const [view, setView] = useState<string>('auth');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [refCode, setRefCode] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  useEffect(() => {
    saveState(state);
  }, [state]);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    await new Promise(r => setTimeout(r, 1000));

    const user = state.users.find(u => u.email === email);
    if (user) {
      setState(prev => ({ ...prev, currentUser: user }));
      setView('dashboard');
    } else {
      alert('Login failed. Please check your email and password.');
    }
    setIsLoading(false);
  };

  const handleRegister = async (e: React.FormEvent) => {
    e.preventDefault();
    if (state.users.some(u => u.email === email)) {
      alert('This email is already registered.');
      return;
    }
    setIsLoading(true);
    await new Promise(r => setTimeout(r, 1500));

    const newUser: User = {
      id: Math.random().toString(36).substr(2, 9),
      email,
      referralCode: email.split('@')[0].toUpperCase() + Math.floor(Math.random() * 1000),
      referredBy: refCode || undefined,
      usdtDepositAddress: 'T' + Math.random().toString(36).substr(2, 33).toUpperCase(),
      capitalBalance: 0,
      profitBalance: 0,
      totalEarned: 0,
      isActive: true,
      isAdmin: false,
      referralCount: 0,
      referralEarnings: 0
    };

    setState(prev => ({
      ...prev,
      users: [...prev.users, newUser],
      currentUser: newUser
    }));
    setView('dashboard');
    setIsLoading(false);
  };

  const handleLogout = () => {
    setState(prev => ({ ...prev, currentUser: null }));
    setView('auth');
  };

  if (!state.currentUser) {
    return (
      <div className="min-h-screen bg-black flex flex-col lg:flex-row relative">
        <div className="flex-1 p-12 lg:p-24 flex flex-col justify-between border-r border-white/5">
          <div className="flex items-center gap-4">
             <div className="w-8 h-8 bg-white"></div>
             <span className="text-2xl font-black uppercase tracking-tighter">QUANTUM</span>
          </div>

          <div className="max-w-xl space-y-12">
            <motion.h1 
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              className="text-7xl lg:text-9xl font-black tracking-tighter leading-[0.85] uppercase"
            >
              Easy <br/> <span className="text-white/20">Earnings.</span>
            </motion.h1>
            <p className="serif italic text-2xl text-white/50 leading-relaxed">
              Simple and secure automated profit plans. We manage the complexity, you enjoy the daily returns.
            </p>
          </div>

          <div className="flex gap-16">
            <div className="space-y-1">
              <p className="text-2xl font-black mono tracking-tighter">12k+</p>
              <p className="text-[10px] font-bold text-white/30 uppercase tracking-widest">Global Users</p>
            </div>
            <div className="space-y-1">
              <p className="text-2xl font-black mono tracking-tighter">$42M</p>
              <p className="text-[10px] font-bold text-white/30 uppercase tracking-widest">Total Profits Paid</p>
            </div>
          </div>
        </div>

        <div className="w-full lg:w-[35%] min-h-screen bg-black flex items-center justify-center p-12 lg:p-24">
          <motion.div 
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            className="w-full max-w-sm space-y-12"
          >
            <div>
              <h2 className="text-[10px] font-black uppercase tracking-[0.5em] text-white/40 mb-2">Member Portal</h2>
              <p className="text-2xl font-bold tracking-tight">Login or Sign Up</p>
            </div>

            <form className="space-y-8" onSubmit={view === 'auth' ? handleLogin : handleRegister}>
              <div className="space-y-2 group">
                <p className="text-[10px] font-black uppercase tracking-widest text-white/30 group-focus-within:text-white transition-colors">Email Address</p>
                <input 
                  type="email" 
                  required
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  className="w-full bg-transparent border-b border-white/20 py-3 outline-none focus:border-white transition-colors font-medium text-white"
                  placeholder="name@email.com"
                />
              </div>

              <div className="space-y-2 group">
                <p className="text-[10px] font-black uppercase tracking-widest text-white/30 group-focus-within:text-white transition-colors">Password</p>
                <input 
                  type="password" 
                  required
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  className="w-full bg-transparent border-b border-white/20 py-3 outline-none focus:border-white transition-colors font-medium text-white"
                  placeholder="••••••••"
                />
              </div>

              {view === 'register' && (
                <div className="space-y-2 group">
                  <p className="text-[10px] font-black uppercase tracking-widest text-white/30">Referral Code (Optional)</p>
                  <input 
                    type="text" 
                    value={refCode}
                    onChange={(e) => setRefCode(e.target.value)}
                    className="w-full bg-transparent border-b border-white/20 py-3 outline-none focus:border-white transition-colors font-mono text-xs uppercase"
                    placeholder="CODE123"
                  />
                </div>
              )}

              <button 
                type="submit"
                disabled={isLoading}
                className="w-full py-5 bg-white text-black text-xs font-black uppercase tracking-[0.3em] hover:bg-white/90 active:scale-[0.98] transition-all flex items-center justify-center gap-4"
              >
                {isLoading ? (
                  <div className="w-4 h-4 border-2 border-black/20 border-t-black rounded-full animate-spin"></div>
                ) : (
                  view === 'auth' ? 'Login' : 'Sign Up'
                )}
              </button>

              <div className="text-center pt-4">
                 <button 
                  type="button"
                  onClick={() => setView(view === 'auth' ? 'register' : 'auth')}
                  className="text-[10px] font-black uppercase tracking-widest text-white/30 hover:text-white transition-colors"
                 >
                   {view === 'auth' ? "Create a new account" : "Back to Login"}
                 </button>
              </div>
            </form>
          </motion.div>
        </div>
      </div>
    );
  }

  return (
    <Layout 
      user={state.currentUser} 
      onLogout={handleLogout} 
      onNavigate={setView}
      currentView={view}
    >
      <AnimatePresence mode="wait">
        <motion.div
          key={view}
          initial={{ opacity: 0, y: 5 }}
          animate={{ opacity: 1, y: 0 }}
          exit={{ opacity: 0, y: -5 }}
          transition={{ duration: 0.3 }}
        >
          {view === 'dashboard' && (
            <Dashboard 
              user={state.currentUser} 
              transactions={state.transactions.filter(tx => tx.userId === state.currentUser?.id)}
              activePackages={state.activePackages.filter(p => (p as any).userId === state.currentUser?.id)}
            />
          )}

          {view === 'wallet' && (
            <Wallet 
              user={state.currentUser} 
              onDepositSim={(a) => setState(simulateDeposit(state, state.currentUser!.id, a))}
              onWithdrawRequest={(amount, address) => {
                if (amount > state.currentUser!.profitBalance) return;
                const newTx = {
                  id: Math.random().toString(36).substr(2, 9),
                  userId: state.currentUser!.id,
                  type: TransactionType.WITHDRAWAL,
                  amount,
                  status: TransactionStatus.PENDING,
                  timestamp: Date.now(),
                  description: `Withdraw to ${address}`
                };
                setState(prev => {
                  const updatedUsers = prev.users.map(u => u.id === state.currentUser?.id ? { ...u, profitBalance: u.profitBalance - amount } : u);
                  return { ...prev, users: updatedUsers, transactions: [newTx, ...prev.transactions], currentUser: updatedUsers.find(u => u.id === state.currentUser?.id) || null };
                });
              }}
            />
          )}

          {view === 'packages' && (
            <div className="space-y-12 max-w-7xl mx-auto pb-24 lg:pb-0">
               <div className="flex flex-col gap-4">
                  <h2 className="text-5xl lg:text-9xl font-black uppercase tracking-tighter leading-none">Investment<br/>Plans.</h2>
                  <p className="serif italic text-xl lg:text-2xl text-white/40 max-w-xl">
                    Pick a plan that fits your budget and start earning daily profits automatically.
                  </p>
               </div>

               {/* Mobile optimized grid: 2 columns on mobile, 3 on desktop */}
               <div className="grid grid-cols-2 md:grid-cols-3 border-t border-l border-white/10">
                 {INITIAL_PACKAGES.map((pkg, idx) => (
                   <div 
                    key={pkg.id} 
                    className="border-r border-b border-white/10 p-6 md:p-12 group hover:bg-white hover:text-black transition-all duration-500"
                   >
                     <div className="space-y-4 md:space-y-8 h-full flex flex-col">
                       <div className="flex justify-between items-start">
                         <h3 className="text-[10px] md:text-xs font-black uppercase tracking-[0.2em] md:tracking-[0.4em]">{pkg.name}</h3>
                         <span className="mono text-[8px] md:text-[10px] font-bold opacity-40 uppercase">{idx + 1}</span>
                       </div>

                       <div className="space-y-1">
                         <p className="text-3xl md:text-6xl font-black mono tracking-tighter leading-none">{pkg.dailyRoi}%</p>
                         <p className="text-[8px] md:text-[10px] font-black uppercase tracking-widest opacity-40">Daily Profit</p>
                       </div>

                       <p className="text-[10px] md:text-sm font-medium leading-tight md:leading-relaxed opacity-60 group-hover:opacity-100 line-clamp-2 md:line-clamp-none">
                         {pkg.description}
                       </p>

                       <div className="mt-auto space-y-4 md:space-y-8 pt-6 md:pt-12">
                         <div className="space-y-2 md:space-y-4">
                            <div className="flex justify-between items-baseline border-b border-white/10 pb-1 md:pb-2 group-hover:border-black/10">
                              <span className="text-[8px] md:text-[10px] font-bold uppercase tracking-widest opacity-40">Min</span>
                              <span className="text-[10px] md:text-sm font-bold mono">${pkg.minAmount}</span>
                            </div>
                            <div className="flex justify-between items-baseline border-b border-white/10 pb-1 md:pb-2 group-hover:border-black/10">
                              <span className="text-[8px] md:text-[10px] font-bold uppercase tracking-widest opacity-40">Max</span>
                              <span className="text-[10px] md:text-sm font-bold mono">${pkg.maxAmount}</span>
                            </div>
                         </div>
                         <button 
                          onClick={() => setView('wallet')}
                          className="w-full py-3 md:py-4 border border-white/20 group-hover:bg-black group-hover:text-white group-hover:border-black text-[8px] md:text-[10px] font-black uppercase tracking-[0.2em] md:tracking-[0.3em] transition-all"
                         >
                           Get Started
                         </button>
                       </div>
                     </div>
                   </div>
                 ))}
               </div>
            </div>
          )}

          {view === 'referrals' && (
            <div className="space-y-24 max-w-7xl mx-auto pb-24 lg:pb-0">
               <div className="flex flex-col lg:flex-row justify-between items-end gap-12">
                  <div className="space-y-6 flex-1">
                    <h1 className="text-6xl lg:text-9xl font-black uppercase tracking-tighter leading-[0.85]">Affiliate<br/>Program.</h1>
                    <p className="serif italic text-2xl text-white/50 max-w-xl">
                      Invite friends and earn bonus rewards when they start their own plans.
                    </p>
                  </div>
                  <div className="w-full lg:w-96 p-10 bg-white text-black space-y-6">
                    <p className="text-[10px] font-black uppercase tracking-widest leading-none">Your Invite Code</p>
                    <p className="text-xl font-black mono tracking-widest truncate">{state.currentUser.referralCode}</p>
                    <button 
                      onClick={() => {
                        navigator.clipboard.writeText(state.currentUser.referralCode);
                        alert('Referral code copied!');
                      }}
                      className="w-full py-3 bg-black text-white text-[10px] font-black uppercase tracking-[0.2em] hover:bg-black/90 transition-all"
                    >
                      Copy Link
                    </button>
                  </div>
               </div>

               <div className="grid grid-cols-1 md:grid-cols-3 border-t border-l border-white/10">
                  {[
                    { level: 1, rate: 10, label: 'Level 1' },
                    { level: 2, rate: 5, label: 'Level 2' },
                    { level: 3, rate: 2, label: 'Level 3' }
                  ].map((tier) => (
                    <div key={tier.level} className="border-r border-b border-white/10 p-12 space-y-8">
                       <p className="text-[10px] font-black uppercase tracking-[0.4em] text-white/40">{tier.label} Friends</p>
                       <div className="flex items-baseline gap-2">
                         <span className="text-6xl font-black mono tracking-tighter">{tier.rate}%</span>
                         <span className="text-[10px] font-bold uppercase text-white/30">Reward</span>
                       </div>
                       <p className="text-xs font-medium text-white/50">Earn {tier.rate}% from the daily profits of friends you invite at this level.</p>
                    </div>
                  ))}
               </div>
            </div>
          )}

          {view === 'admin' && (
            <AdminPanel 
              state={state}
              onUpdateSettings={(s) => setState(prev => ({...prev, platformSettings: {...prev.platformSettings, ...s}}))}
              onTriggerRoi={() => {
                setState(processDailyRoi(state));
                alert('Daily profits have been distributed.');
              }}
              onManageWithdrawal={(id, status) => {
                const tx = state.transactions.find(t => t.id === id);
                if (!tx) return;
                setState(prev => {
                  const updatedTxs = prev.transactions.map(t => t.id === id ? {...t, status} : t);
                  let updatedUsers = prev.users;
                  if (status === TransactionStatus.REJECTED) {
                    updatedUsers = prev.users.map(u => u.id === tx.userId ? {...u, profitBalance: u.profitBalance + tx.amount} : u);
                  }
                  return {...prev, transactions: updatedTxs, users: updatedUsers, currentUser: prev.currentUser ? updatedUsers.find(u => u.id === prev.currentUser?.id) || null : null};
                });
              }}
            />
          )}
        </motion.div>
      </AnimatePresence>
    </Layout>
