export enum TransactionType {
  DEPOSIT = 'DEPOSIT',
  WITHDRAWAL = 'WITHDRAWAL',
  ROI = 'ROI',
  REFERRAL = 'REFERRAL'
}

export enum TransactionStatus {
  PENDING = 'PENDING',
  COMPLETED = 'COMPLETED',
  REJECTED = 'REJECTED'
}

export interface Package {
  id: string;
  name: string;
  minAmount: number;
  maxAmount: number;
  dailyRoi: number;
  durationDays: number;
  description: string;
}

export interface UserPackage {
  id: string;
  packageId: string;
  amount: number;
  activatedAt: number;
  isActive: boolean;
  totalEarned: number;
  userId: string;
}

export interface Transaction {
  id: string;
  userId: string;
  type: TransactionType;
  amount: number;
  status: TransactionStatus;
  txHash?: string;
  timestamp: number;
  description: string;
}

export interface User {
  id: string;
  email: string;
  referralCode: string;
  referredBy?: string;
  usdtDepositAddress: string;
  withdrawalAddress?: string;
  capitalBalance: number;
  profitBalance: number;
  totalEarned: number;
  isActive: boolean;
  isAdmin: boolean;
  referralCount: number;
  referralEarnings: number;
  welcomeBonus: number;
}

export interface AppState {
  currentUser: User | null;
  users: User[];
  packages: Package[];
  activePackages: UserPackage[];
  transactions: Transaction[];
  platformSettings: {
    isRoiEnabled: boolean;
    referralLevels: { level: number; percentage: number }[];
    minWithdrawal: number;
    platformPaused: boolean;
    roiOverride?: number;
  };
}

import { AppState, User, Transaction, TransactionType, TransactionStatus, UserPackage } from './types.ts';
import { INITIAL_PACKAGES, REF_LEVELS } from './constants.tsx';

const STORAGE_KEY = 'usdt_earning_pool_state';

const generateId = () => Math.random().toString(36).substr(2, 9);

const initialState: AppState = {
  currentUser: null,
  users: [
    {
      id: 'admin',
      email: 'admin@quantumearn.com',
      referralCode: 'ADMIN_ROOT',
      usdtDepositAddress: 'TADMIN1234567890',
      capitalBalance: 0,
      profitBalance: 0,
      totalEarned: 0,
      isActive: true,
      isAdmin: true,
      referralCount: 0,
      referralEarnings: 0,
      welcomeBonus: 0
    }
  ],
  packages: INITIAL_PACKAGES,
  activePackages: [],
  transactions: [],
  platformSettings: {
    isRoiEnabled: true,
    referralLevels: REF_LEVELS,
    minWithdrawal: 10,
    platformPaused: false
  }
};

export const loadState = (): AppState => {
  const saved = localStorage.getItem(STORAGE_KEY);
  if (saved) {
    try {
      return JSON.parse(saved);
    } catch (e) {
      return initialState;
    }
  }
  return initialState;
};

export const saveState = (state: AppState) => {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
};

export const simulateDeposit = (state: AppState, userId: string, amount: number): AppState => {
  const user = state.users.find(u => u.id === userId);
  if (!user) return state;

  const newTx: Transaction = {
    id: generateId(),
    userId,
    type: TransactionType.DEPOSIT,
    amount,
    status: TransactionStatus.COMPLETED,
    txHash: '0x' + generateId() + generateId(),
    timestamp: Date.now(),
    description: `Deposit of ${amount} USDT added to plan funds.`
  };

  // Check if amount matches a package floor exactly for activation/upgrade
  // Rule: Users must fund exact amount of any package to activate
  const pkg = state.packages.find(p => amount === p.minAmount);

  let newState = {
    ...state,
    users: state.users.map(u => u.id === userId ? {
      ...u,
      capitalBalance: u.capitalBalance + amount
    } : u),
    transactions: [newTx, ...state.transactions],
  };

  if (pkg) {
    // Check if user already has an active package to "upgrade"
    const existingActiveIndex = newState.activePackages.findIndex(ap => ap.userId === userId && ap.isActive);

    const newActivePkg: UserPackage = {
      id: generateId(),
      packageId: pkg.id,
      amount,
      activatedAt: Date.now(),
      isActive: true,
      totalEarned: 0,
      userId
    };

    if (existingActiveIndex !== -1) {
      // Deactivate old one and add new one (Upgrade)
      const updatedActive = [...newState.activePackages];
      updatedActive[existingActiveIndex] = { ...updatedActive[existingActiveIndex], isActive: false };
      newState.activePackages = [...updatedActive, newActivePkg];
    } else {
      newState.activePackages = [...newState.activePackages, newActivePkg];
    }
  }

  if (newState.currentUser?.id === userId) {
    newState.currentUser = newState.users.find(u => u.id === userId) || null;
  }

  return newState;
};

export const processDailyRoi = (state: AppState): AppState => {
  if (!state.platformSettings.isRoiEnabled || state.platformSettings.platformPaused) return state;

  let newState = { ...state };
  const roiTransactions: Transaction[] = [];

  const updatedActivePackages = state.activePackages.map(ap => {
    if (!ap.isActive) return ap;

    const pkg = state.packages.find(p => p.id === ap.packageId);
    if (!pkg) return ap;

    const dailyPercent = state.platformSettings.roiOverride || pkg.dailyRoi;
    const earnings = ap.amount * (dailyPercent / 100);

    roiTransactions.push({
      id: generateId(),
      userId: ap.userId,
      type: TransactionType.ROI,
      amount: earnings,
      status: TransactionStatus.COMPLETED,
      timestamp: Date.now(),
      description: `Daily profit from ${pkg.name}`
    });

    distributeReferrals(newState, ap.userId, earnings, roiTransactions);

    return {
      ...ap,
      totalEarned: ap.totalEarned + earnings
    };
  });

  const userUpdates = new Map<string, number>();
  roiTransactions.forEach(tx => {
    userUpdates.set(tx.userId, (userUpdates.get(tx.userId) || 0) + tx.amount);
  });

  newState.users = newState.users.map(u => {
    const bonus = userUpdates.get(u.id);
    if (bonus) {
      return {
        ...u,
        profitBalance: u.profitBalance + bonus,
        totalEarned: u.totalEarned + bonus
      };
    }
    return u;
  });

  newState.activePackages = updatedActivePackages;
  newState.transactions = [...roiTransactions, ...newState.transactions];

  if (newState.currentUser) {
    newState.currentUser = newState.users.find(u => u.id === newState.currentUser?.id) || null;
  }

  return newState;
};

const distributeReferrals = (state: AppState, userId: string, earnings: number, transactions: Transaction[]) => {
  let currentUser = state.users.find(u => u.id === userId);
  if (!currentUser || !currentUser.referredBy) return;

  let currentLevel = 1;
  let referrerId = currentUser.referredBy;

  while (currentLevel <= state.platformSettings.referralLevels.length) {
    const referrer = state.users.find(u => u.referralCode === referrerId || u.id === referrerId);
    if (!referrer) break;

    const config = state.platformSettings.referralLevels.find(l => l.level === currentLevel);
    if (config) {
      const commission = earnings * (config.percentage / 100);
      transactions.push({
        id: generateId(),
        userId: referrer.id,
        type: TransactionType.REFERRAL,
        amount: commission,
        status: TransactionStatus.COMPLETED,
        timestamp: Date.now(),
        description: `Level ${currentLevel} friend bonus from User ${userId}`
      });
    }

    if (!referrer.referredBy) break;
    referrerId = referrer.referredBy;
    currentLevel++;
  }
};

